+@page "/board"
+@rendermode InteractiveServer
+@using sv_7c108f9f516f4eb292d5505c0c8c740f.Services
+@inject ITaskService TaskService
+
+<PageTitle>Kanban Board</PageTitle>
+
+<h3 class="mb-3">Project Board</h3>
+
+@if (_loading)
+{
+    <div class="d-flex justify-content-center my-5">
+        <div class="spinner-border" role="status">
+            <span class="visually-hidden">Loading…</span>
+        </div>
+    </div>
+}
+else if (_error is not null)
+{
+    <div class="alert alert-danger" role="alert">
+        <strong>Error:</strong> @_error
+        <button class="btn btn-sm btn-outline-danger ms-3" @onclick="LoadTasksAsync">Retry</button>
+    </div>
+}
+else
+{
+    @* ── Stats bar ── *@
+    <div class="row g-2 mb-3">
+        <div class="col"><div class="card text-center p-2"><small class="text-muted">Total</small><div class="fw-bold">@_allTasks.Count</div></div></div>
+        <div class="col"><div class="card text-center p-2"><small class="text-muted">To Do</small><div class="fw-bold">@GetColumnTasks("To Do").Count</div></div></div>
+        <div class="col"><div class="card text-center p-2"><small class="text-muted">In Progress</small><div class="fw-bold">@GetColumnTasks("In Progress").Count</div></div></div>
+        <div class="col"><div class="card text-center p-2"><small class="text-muted">Done</small><div class="fw-bold">@GetColumnTasks("Done").Count</div></div></div>
+        <div class="col"><div class="card text-center p-2"><small class="text-muted">Overdue</small><div class="fw-bold text-danger">@_allTasks.Count(t => t.DueDate.Date < DateTime.Today)</div></div></div>
+    </div>
+
+    @* ── Search bar ── *@
+    <div class="mb-3">
+        <input type="text" class="form-control" placeholder="Search tasks by title…" @bind="_searchTerm" @bind:event="oninput" />
+    </div>
+
+    @* ── Columns ── *@
+    <div class="row g-3">
+        @foreach (var column in _columns)
+        {
+            var tasks = GetFilteredColumnTasks(column);
+            <div class="col-md-4">
+                <div class="card h-100">
+                    <div class="card-header d-flex justify-content-between align-items-center">
+                        <span class="fw-bold">@column</span>
+                        <span class="badge bg-secondary rounded-pill">@GetColumnTasks(column).Count</span>
+                    </div>
+                    <div class="card-body d-flex flex-column gap-2" style="min-height:200px;overflow-y:auto;">
+                        @foreach (var task in tasks)
+                        {
+                            <div class="card shadow-sm">
+                                <div class="card-body p-2">
+                                    <div class="fw-semibold mb-1">@task.Title</div>
+                                    <div class="d-flex justify-content-between align-items-center mb-1">
+                                        <small class="text-muted">@task.Assignee</small>
+                                        <span class="badge @GetPriorityClass(task.Priority)">@task.Priority</span>
+                                    </div>
+                                    <div class="d-flex justify-content-between align-items-center">
+                                        <small class="text-muted">@task.DueDate.ToString("MMM dd")</small>
+                                        <div>
+                                            @if (GetColumnIndex(column) > 0)
+                                            {
+                                                <button class="btn btn-sm btn-outline-secondary me-1" @onclick="() => MoveTaskAsync(task, -1)" disabled="@_moving">◀ Move Left</button>
+                                            }
+                                            @if (GetColumnIndex(column) < _columns.Length - 1)
+                                            {
+                                                <button class="btn btn-sm btn-outline-secondary" @onclick="() => MoveTaskAsync(task, 1)" disabled="@_moving">Move Right ▶</button>
+                                            }
+                                        </div>
+                                    </div>
+                                </div>
+                            </div>
+                        }
+
+                        @if (_addingToColumn == column)
+                        {
+                            <div class="card border-primary">
+                                <div class="card-body p-2">
+                                    <input type="text" class="form-control form-control-sm mb-1" placeholder="Title" @bind="_newTitle" />
+                                    <input type="text" class="form-control form-control-sm mb-1" placeholder="Assignee" @bind="_newAssignee" />
+                                    <select class="form-select form-select-sm mb-1" @bind="_newPriority">
+                                        <option value="High">High</option>
+                                        <option value="Medium">Medium</option>
+                                        <option value="Low">Low</option>
+                                    </select>
+                                    <input type="date" class="form-control form-control-sm mb-2" @bind="_newDueDate" />
+                                    <div class="d-flex gap-1">
+                                        <button class="btn btn-sm btn-primary flex-fill" @onclick="SaveNewTaskAsync" disabled="@_saving">Save</button>
+                                        <button class="btn btn-sm btn-outline-secondary flex-fill" @onclick="CancelAdd">Cancel</button>
+                                    </div>
+                                </div>
+                            </div>
+                        }
+                    </div>
+                    <div class="card-footer">
+                        <button class="btn btn-sm btn-outline-primary w-100" @onclick="() => StartAdd(column)">+ Add Task</button>
+                    </div>
+                </div>
+            </div>
+        }
+    </div>
+}
+
+@code {
+    private readonly string[] _columns = ["To Do", "In Progress", "Done"];
+
+    private List<TaskItem> _allTasks = new();
+    private bool _loading = true;
+    private string? _error;
+    private string _searchTerm = string.Empty;
+
+    // Moving state
+    private bool _moving;
+
+    // Add-task form state
+    private string? _addingToColumn;
+    private string _newTitle = string.Empty;
+    private string _newAssignee = string.Empty;
+    private string _newPriority = "Medium";
+    private DateTime _newDueDate = DateTime.Today.AddDays(7);
+    private bool _saving;
+
+    protected override async Task OnInitializedAsync()
+    {
+        await LoadTasksAsync();
+    }
+
+    private async Task LoadTasksAsync()
+    {
+        try
+        {
+            _loading = true;
+            _error = null;
+            _allTasks = await TaskService.GetAllTasksAsync();
+        }
+        catch (Exception ex)
+        {
+            _error = ex.Message;
+        }
+        finally
+        {
+            _loading = false;
+        }
+    }
+
+    private List<TaskItem> GetColumnTasks(string status)
+        => _allTasks.Where(t => t.Status == status).ToList();
+
+    private List<TaskItem> GetFilteredColumnTasks(string status)
+        => _allTasks
+            .Where(t => t.Status == status &&
+                        (string.IsNullOrWhiteSpace(_searchTerm) ||
+                         t.Title.Contains(_searchTerm, StringComparison.OrdinalIgnoreCase)))
+            .ToList();
+
+    private int GetColumnIndex(string column) => Array.IndexOf(_columns, column);
+
+    private static string GetPriorityClass(string priority) => priority switch
+    {
+        "High" => "bg-danger",
+        "Medium" => "bg-warning text-dark",
+        "Low" => "bg-success",
+        _ => "bg-secondary"
+    };
+
+    private async Task MoveTaskAsync(TaskItem task, int direction)
+    {
+        var currentIndex = GetColumnIndex(task.Status);
+        var newIndex = currentIndex + direction;
+        if (newIndex < 0 || newIndex >= _columns.Length) return;
+
+        try
+        {
+            _moving = true;
+            var newStatus = _columns[newIndex];
+            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
+            var idx = _allTasks.FindIndex(t => t.Id == task.Id);
+            if (idx >= 0)
+                _allTasks[idx] = task with { Status = newStatus };
+        }
+        catch (Exception ex)
+        {
+            _error = ex.Message;
+        }
+        finally
+        {
+            _moving = false;
+        }
+    }
+
+    private void StartAdd(string column)
+    {
+        _addingToColumn = column;
+        _newTitle = string.Empty;
+        _newAssignee = string.Empty;
+        _newPriority = "Medium";
+        _newDueDate = DateTime.Today.AddDays(7);
+    }
+
+    private void CancelAdd() => _addingToColumn = null;
+
+    private async Task SaveNewTaskAsync()
+    {
+        if (string.IsNullOrWhiteSpace(_newTitle) || _addingToColumn is null) return;
+
+        try
+        {
+            _saving = true;
+            var created = await TaskService.CreateTaskAsync(_newTitle, _newAssignee, _newPriority, _newDueDate);
+            // CreateTaskAsync defaults status; override to match the target column
+            var finalTask = created.Status == _addingToColumn
+                ? created
+                : created with { Status = _addingToColumn };
+
+            if (finalTask.Status != created.Status)
+                await TaskService.UpdateTaskStatusAsync(finalTask.Id, _addingToColumn);
+
+            _allTasks.Add(finalTask);
+            _addingToColumn = null;
+        }
+        catch (Exception ex)
+        {
+            _error = ex.Message;
+        }
+        finally
+        {
+            _saving = false;
+        }
+    }
+}
+

